async function main() {
  console.log('═══════════════════════════════════════════════════════')
  console.log('  ATLAS MATERIAL PRICE SEED — 10 Trades × 15 Materials')
  console.log('═══════════════════════════════════════════════════════\n')

  // Count existing records
  const existing = await prisma.materialPrice.count()
  if (existing > 0) {
    console.log(`Found ${existing} existing MaterialPrice records.`)
    console.log('Skipping seed to avoid duplicates. Delete existing records first if you want to re-seed.\n')
    await prisma.$disconnect()
    return
  }

  const tradeCounts: Record<string, number> = {}
  let total = 0

  for (const mat of materials) {
    await prisma.materialPrice.create({
      data: {
        name: mat.name,
        trade: mat.trade,
        unit: mat.unit,
        currentPrice: mat.currentPrice,
        hdPrice: mat.currentPrice, // Initial price is from Home Depot
        category: mat.category,
        sourceUrl: mat.sourceUrl,
        primarySource: 'HomeDepot',
      },
    })

    tradeCounts[mat.trade] = (tradeCounts[mat.trade] || 0) + 1
    total++
  }

  console.log('Seed complete!\n')
  console.log('  By Trade:')
  for (const [trade, count] of Object.entries(tradeCounts).sort()) {
    console.log(`    ${trade}: ${count} materials`)
  }
  console.log(`\n  Total MaterialPrice records created: ${total}\n`)

  await prisma.$disconnect()
}

main().catch((e) => {
  console.error(e)
  prisma.$disconnect()
  process.exit(1)
})
